import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tickets, setTickets] = useState(1);
  const [booking, setBooking] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) { navigate('/login'); return; }
    fetchEvent();
  }, [id]);

  const fetchEvent = async () => {
    try {
      const res = await API.get(`/events/${id}`);
      setEvent(res.data.event);
    } catch { setError('Event not found'); }
    finally { setLoading(false); }
  };

  const handleBook = async () => {
    const token = localStorage.getItem('token');
    if (!token) { navigate('/login'); return; }
    setError(''); setBooking(true);
    try {
      await API.post('/bookings', { eventId: id, numberOfTickets: tickets });
      setSuccess('🎉 Booking confirmed! Redirecting to your bookings...');
      setTimeout(() => navigate('/my-bookings'), 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed. Please try again.');
    } finally { setBooking(false); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', background: '#fdf6f3' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🌸</div>
        <p style={{ color: '#c9a99a', fontFamily: "'DM Sans', sans-serif" }}>Loading event...</p>
      </div>
    </div>
  );

  if (error && !event) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', background: '#fdf6f3' }}>
      <div style={{ textAlign: 'center', fontFamily: "'DM Sans', sans-serif" }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>😕</div>
        <h2 style={{ color: '#2d1f1f' }}>Event Not Found</h2>
        <button onClick={() => navigate('/home')} style={{ marginTop: '1rem', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', padding: '10px 24px', borderRadius: '10px', cursor: 'pointer', fontFamily: "'DM Sans', sans-serif" }}>Go Home</button>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight: '100vh', background: '#fdf6f3', fontFamily: "'DM Sans', sans-serif" }}>

      {/* Hero Image */}
      <div style={{ position: 'relative', height: '380px' }}>
        <img src={event.image || 'https://images.unsplash.com/photo-1470229722913-7c0e2dbbafd3?w=1200&q=80'}
          alt={event.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(45,31,31,0.85) 0%, rgba(45,31,31,0.3) 60%, transparent 100%)' }} />

        {/* Back button */}
        <button onClick={() => navigate('/home')} style={{ position: 'absolute', top: '1.5rem', left: '1.5rem', background: 'rgba(253,246,243,0.9)', backdropFilter: 'blur(10px)', border: 'none', color: '#c9a99a', padding: '8px 16px', borderRadius: '20px', cursor: 'pointer', fontWeight: '600', fontSize: '0.82rem', fontFamily: "'DM Sans', sans-serif" }}>
          ← Back
        </button>

        <div style={{ position: 'absolute', bottom: '2rem', left: '2rem', color: 'white' }}>
          <span style={{ background: 'rgba(201,169,154,0.9)', backdropFilter: 'blur(10px)', padding: '5px 14px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: '700', marginBottom: '10px', display: 'inline-block' }}>{event.category}</span>
          <h1 style={{ fontSize: 'clamp(1.8rem, 4vw, 3rem)', fontWeight: '700', marginTop: '8px', fontFamily: "'Cormorant Garamond', serif", textShadow: '0 2px 10px rgba(0,0,0,0.3)' }}>{event.name}</h1>
        </div>
      </div>

      {/* Content */}
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '2rem', display: 'grid', gridTemplateColumns: '1fr 340px', gap: '2rem', alignItems: 'start' }}>

        {/* Left - Details */}
        <div>
          {/* About */}
          <div style={{ background: 'white', borderRadius: '20px', padding: '1.8rem', marginBottom: '1.5rem', boxShadow: '0 4px 20px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3' }}>
            <h2 style={{ color: '#2d1f1f', fontWeight: '700', marginBottom: '1rem', fontFamily: "'Cormorant Garamond', serif", fontSize: '1.3rem' }}>About This Event</h2>
            <p style={{ color: '#6b5a55', lineHeight: '1.8', fontSize: '0.9rem' }}>{event.description || 'Join us for an amazing experience you will never forget!'}</p>
          </div>

          {/* Details Grid */}
          <div style={{ background: 'white', borderRadius: '20px', padding: '1.8rem', boxShadow: '0 4px 20px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3' }}>
            <h2 style={{ color: '#2d1f1f', fontWeight: '700', marginBottom: '1.2rem', fontFamily: "'Cormorant Garamond', serif", fontSize: '1.3rem' }}>Event Details</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              {[
                { icon: '📅', label: 'Date', value: new Date(event.date).toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) },
                { icon: '🕐', label: 'Time', value: event.time },
                { icon: '📍', label: 'Venue', value: event.venue },
                { icon: '🏷️', label: 'Category', value: event.category },
                { icon: '🎫', label: 'Available', value: `${event.availableSeats} seats` },
                { icon: '👥', label: 'Total Seats', value: event.totalSeats },
              ].map(item => (
                <div key={item.label} style={{ background: '#fdf6f3', borderRadius: '14px', padding: '1rem', display: 'flex', gap: '10px', alignItems: 'flex-start', border: '1px solid #f5e8e3' }}>
                  <span style={{ fontSize: '1.2rem' }}>{item.icon}</span>
                  <div>
                    <p style={{ color: '#c0a0a0', fontSize: '0.7rem', marginBottom: '3px', fontWeight: '600' }}>{item.label.toUpperCase()}</p>
                    <p style={{ color: '#2d1f1f', fontWeight: '600', fontSize: '0.85rem' }}>{item.value}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Right - Booking Card */}
        <div style={{ background: 'white', borderRadius: '20px', padding: '1.8rem', boxShadow: '0 4px 20px rgba(201,169,154,0.15)', border: '1px solid #f5e8e3', position: 'sticky', top: '90px' }}>
          <div style={{ marginBottom: '1.5rem', paddingBottom: '1.5rem', borderBottom: '1px solid #f5e8e3' }}>
            <p style={{ color: '#c9a99a', fontSize: '2.2rem', fontWeight: '800', margin: 0 }}>₹{event.price}</p>
            <p style={{ color: '#a08880', fontSize: '0.8rem', margin: 0 }}>per ticket</p>
          </div>

          {/* Messages */}
          {error && (
            <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '11px 14px', borderRadius: '12px', marginBottom: '1rem', fontSize: '0.82rem' }}>⚠️ {error}</div>
          )}
          {success && (
            <div style={{ background: '#edf5f0', border: '1px solid #b8d8c8', color: '#3a7a5a', padding: '11px 14px', borderRadius: '12px', marginBottom: '1rem', fontSize: '0.82rem' }}>{success}</div>
          )}

          {event.availableSeats > 0 && event.status === 'upcoming' ? (
            <>
              {/* Ticket selector */}
              <div style={{ marginBottom: '1.2rem' }}>
                <p style={{ color: '#6b5a55', fontSize: '0.82rem', fontWeight: '600', marginBottom: '10px' }}>Number of Tickets</p>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', background: '#fdf6f3', borderRadius: '12px', padding: '10px 14px', border: '1px solid #f5e8e3' }}>
                  <button onClick={() => setTickets(Math.max(1, tickets - 1))} style={{ width: '32px', height: '32px', borderRadius: '50%', background: 'white', border: '1.5px solid #f0ddd7', color: '#c9a99a', cursor: 'pointer', fontSize: '1.1rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>−</button>
                  <span style={{ color: '#2d1f1f', fontWeight: '800', fontSize: '1.3rem', flex: 1, textAlign: 'center' }}>{tickets}</span>
                  <button onClick={() => setTickets(Math.min(event.availableSeats, tickets + 1))} style={{ width: '32px', height: '32px', borderRadius: '50%', background: 'white', border: '1.5px solid #f0ddd7', color: '#c9a99a', cursor: 'pointer', fontSize: '1.1rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>+</button>
                </div>
              </div>

              {/* Price breakdown */}
              <div style={{ background: '#fdf6f3', borderRadius: '12px', padding: '1rem', marginBottom: '1.2rem', border: '1px solid #f5e8e3' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#a08880', fontSize: '0.82rem', marginBottom: '8px' }}>
                  <span>₹{event.price} × {tickets} tickets</span>
                  <span>₹{event.price * tickets}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#a08880', fontSize: '0.82rem', marginBottom: '8px' }}>
                  <span>Convenience fee</span>
                  <span style={{ color: '#8aad9a' }}>FREE</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#2d1f1f', fontWeight: '800', borderTop: '1px solid #f0ddd7', paddingTop: '8px', marginTop: '4px' }}>
                  <span>Total Amount</span>
                  <span style={{ color: '#c9a99a', fontSize: '1.1rem' }}>₹{event.price * tickets}</span>
                </div>
              </div>

              {/* Book Button */}
              <button onClick={handleBook} disabled={booking || !!success} style={{
                width: '100%', padding: '14px',
                background: booking || success ? 'rgba(201,169,154,0.5)' : 'linear-gradient(135deg, #c9a99a, #b8887a)',
                color: 'white', border: 'none', borderRadius: '14px', cursor: booking || success ? 'not-allowed' : 'pointer',
                fontWeight: '700', fontSize: '0.95rem', fontFamily: "'DM Sans', sans-serif",
                boxShadow: '0 6px 20px rgba(201,169,154,0.4)', transition: 'all 0.2s', letterSpacing: '0.3px'
              }}>
                {booking ? '⏳ Confirming...' : success ? '✅ Booked!' : '🎟️ Confirm Booking'}
              </button>

              <p style={{ textAlign: 'center', color: '#c0a0a0', fontSize: '0.75rem', marginTop: '0.8rem' }}>
                🔒 Secure booking • Instant confirmation
              </p>
            </>
          ) : (
            <div style={{ textAlign: 'center', padding: '1.5rem', background: '#fdf6f3', borderRadius: '12px' }}>
              <div style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>😔</div>
              <p style={{ color: '#a08880', fontSize: '0.85rem' }}>
                {event.availableSeats === 0 ? 'This event is sold out.' : 'Booking not available.'}
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
export default EventDetails;
